class NetworkLogger {
    static let shared = NetworkLogger()
    
    func logFullRequest(url: String, method: String, headers: [String: String], body: Data?, userId: String?) {
        NSLog("🌍 FULL REQUEST - URL: %@", url)
        NSLog("🌍 FULL REQUEST - Method: %@", method)
        NSLog("🌍 FULL REQUEST - User ID: %@", userId ?? "Anonymous")
        
        for (key, value) in headers {
            NSLog("🌍 HEADER - %@: %@", key, value)
        }
        
        if let bodyData = body, let bodyString = String(data: bodyData, encoding: .utf8) {
            NSLog("🌍 REQUEST BODY: %@", bodyString)
            print("🌍 Full request body: \(bodyString)")
        }
    }
    
    func logFullResponse(url: String, statusCode: Int, headers: [AnyHashable: Any], body: Data?, userId: String?) {
        NSLog("🌏 FULL RESPONSE - URL: %@", url)
        NSLog("🌏 FULL RESPONSE - Status: %d", statusCode)
        NSLog("🌏 FULL RESPONSE - User ID: %@", userId ?? "Anonymous")
        
        for (key, value) in headers {
            NSLog("🌏 RESPONSE HEADER - %@: %@", "\(key)", "\(value)")
        }
        
        if let bodyData = body, let bodyString = String(data: bodyData, encoding: .utf8) {
            NSLog("🌏 RESPONSE BODY: %@", bodyString)
            print("🌏 Full response body: \(bodyString)")
        }
    }
}

